// This function calculates the total cost of an order.
public static int calculateOrderCost(String orderString, Map<String, Integer> priceList) {
    // Splitting the order string into data based on whitespace
    String[] orderData = orderString.split("\\s+");

    // Splitting the product details from the first element in the array
    String[] productDetails = orderData[0].split("–");

    // Getting the price of the product from the price list using the product name as key
    int productPrice = priceList.get(productDetails[1]);

    // Converting the quantity string to an integer and multiplying it with the product price
    int orderPrice = Integer.parseInt(orderData[1]) * productPrice;

    return orderPrice;
}
