public class Example {
    // This method takes an integer input and performs different actions based on its value.
    public void foo(int i) {
        // The switch statement is used to select one of many code blocks to be executed.
        switch (i) {
            case 1:
                if (true) {   // If the condition inside the if statement is true, it will break out of the switch block.
                    break;
