public int score(Candidate candidate, MedicalExam medicalExam, ScoringGuide scoringGuide) {
    int result = 0;
    int healthLevel = 0;

    // Massacre: This method calculates the score based on the candidate's health level and the exam results.
    if (candidate.getHealth() > medicalExam.getResult()) {
        healthLevel = 1; // If the candidate has a higher health than the result, the score is 1
    } else if (candidate.getHealth() == medicalExam.getResult()) {
        healthLevel = 0; // If the candidate has the same health as the result, the score is 0
    } else {
        healthLevel = -1; // If the candidate has a lower health than the result, the score is -1
    }

    if (healthLevel == 1) {
        result += scoringGuide.getScoreForHigherHealth();
    } else if (healthLevel == 0) {
        result += scoringGuide.getScoreForSameHealth();
    } else {
        result += scoringGuide.getScoreForLowerHealth();
    }

    // long body code
    return result;
}
```
