// This method builds the wall based on the order string and price list.
public void buildWall(String orderString, Map<String, Integer> priceList) {
    // Split the order string into an array of words using whitespace as delimiter
    String[] orderData = orderString.split("\\s+");

    // Split the first element of the order data (product details) into separate components
    String[] productDetails = orderData[0].split("–");

    // Get the price for the product from the price list based on the second component of the product details
    int productPrice = priceList.get(productDetails[1]);

    // Convert the second element of the order data (order quantity) to an integer and multiply it by the product price
    int orderPrice = Integer.parseInt(orderData[1]) * productPrice;
}
```

