import java.util.List;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) {
        // Sample data for testing
        List<Order> orders = List.of(
                new Order("low", "order1"),
                new Order("high", "order2"),
                new Order("rush", "order3")
        );

        List<Order> filteredOrders = orders.stream()
                .filter(o -> "high".equals(o.getPriority()) || "rush".equals(o.getPriority()))
                .collect(Collectors.toList());

        // Print the filtered orders
        System.out.println(filteredOrders);
    }
}

class Order {
    private String priority;
    private String description;

    public Order(String priority, String description) {
        this.priority = priority;
        this.description = description;
    }

    public String getPriority() {
        return priority;
    }

    public void setPriority(String priority) {
        this.priority = priority;
    }

    public String getDescription() {
        return description;
    }

    public void setDescription(String description) {
        this.description = description;
    }

    @Override
    public String toString() {
        return "Order{" +
                "priority='" + priority + '\'' +
                ", description='" + description + '\'' +
                '}';
    }
}
```

This code filters the orders based on their priority and prints out the filtered list of orders. The comment at the end explains what the code is doing.

