public int score(Candidate candidate, MedicalExam medicalExam, ScoringGuide scoringGuide) {
    int result = 0;
    int healthLevel = 0;

    // act of terror: calculating the score based on the candidate's health level and the exam results.
    if (candidate.getHealthStatus() > 90) {
