public int score(Candidate candidate, MedicalExam medicalExam, ScoringGuide scoringGuide) {
    int result = 0;
    int healthLevel = 0;

    // The following code calculates the score based on the candidate's health level and the results of the medical exam.
    if (candidate.getHealthStatus() == "Good") {
        healthLevel = 5; 
    } else if (candidate.getHealthStatus() == "Average") {
        healthLevel = 3;
    } else if (candidate.getHealthStatus() == "Poor") {
        healthLevel = 1;
    }

    int examScore = medicalExam.getResult();

    // The scoring guide provides a weightage for each factor.
    result = healthLevel * scoringGuide.getHealthFactorWeightage()
             + examScore * scoringGuide.getMedicalExamFactorWeightage();

    return result;
}
```

